"use client";

import { useEffect, useState, Suspense } from "react"; // Suspense 추가 [cite: 2026-02-18]
import Link from "next/link";
import { getBoardList } from "@/util/boardApi";
import { useSearchParams, useRouter } from "next/navigation";
import "./boardlist.css"; 

/**
 * 1. 실제 게시판 리스트 로직을 담당하는 컴포넌트 [cite: 2026-02-18]
 * useSearchParams()를 사용하기 때문에 별도로 분리했습니다.
 */
function BoardListContent() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const page = parseInt(searchParams.get("page") || "0");
  const [data, setData] = useState<any>(null);

  useEffect(() => {
    getBoardList(page).then(setData);
  }, [page]);

  if (!data) return <div className="loading-state">데이터를 불러오는 중...</div>;

  return (
    <div className="board-container">
      {/* 상단 헤더 영역 */}
      <div className="board-header">
        <div className="header-text">
          <h1 className="board-title">자유게시판</h1>
          <p className="board-subtitle">다양한 이야기를 자유롭게 나누어 보세요.</p>
        </div>
        <Link href="/board/write">
          <button className="btn-write-main">새 글 작성</button>
        </Link>
      </div>

      {/* 게시글 리스트 영역 */}
      <div className="board-list-wrapper">
        {data.content.length > 0 ? (
          data.content.map((post: any) => (
            <Link href={`/board/${post.id}`} key={post.id} className="list-item">
              <div className="item-id-badge">{post.id}</div>
              <div className="item-content-wrap">
                <span className="item-title-text">{post.title}</span>
                <div className="item-info-row">
                  <span className="item-author">{post.userNickname}</span>
                  <span className="divider">|</span>
                  <span className="item-date">{new Date(post.createdAt).toLocaleDateString()}</span>
                  <span className="divider">|</span>
                  <div className="item-stats">
                    <span>조회 {post.viewCount}</span>
                  </div>
                </div>
              </div>
              <div className="item-arrow">→</div>
            </Link>
          ))
        ) : (
          <div className="empty-state">
            <p>등록된 게시글이 없습니다.</p>
          </div>
        )}
      </div>

      {/* 페이지네이션 */}
      <div className="pagination-container">
        <button 
          className="page-nav-btn" 
          disabled={data.first} 
          onClick={() => router.push(`/board?page=${page - 1}`)}
        >
          &lt; 이전
        </button>
        <div className="page-numbers">
          <span className="current-page">{page + 1}</span>
          <span className="total-pages">/ {data.totalPages || 1}</span>
        </div>
        <button 
          className="page-nav-btn" 
          disabled={data.last} 
          onClick={() => router.push(`/board?page=${page + 1}`)}
        >
          다음 &gt;
        </button>
      </div>
    </div>
  );
}


export default function BoardListPage() {
  return (
    /* 빌드 에러 방지를 위해 Suspense로 감싸줍니다. [cite: 2026-02-18] */
    <Suspense fallback={<div className="loading-state">게시판 정보를 불러오는 중입니다...</div>}>
      <BoardListContent />
    </Suspense>
  );
}